        {"id": 31, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "The intertextuality of this novel points to Dostoyevsky."}, "answer": "Intertekstualnost ovog romana upućuje na Dostojevskog.", "hint": "Nominalna fraza + glagol + prijedlog"},
        {"id": 32, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "The lyric subject expresses deep existential anxiety."}, "answer": "Lirski subjekt izražava duboku egzistencijalnu anksioznost.", "hint": "Historijski prezent + složena imenička fraza"},
        {"id": 33, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "It could be interpreted that the author deliberately uses the contrast between light and darkness."}, "answer": "Moglo bi se tumačiti da autor namjerno koristi kontrast između svjetlosti i tame.", "hint": "Kondicional za interpretaciju"},
        {"id": 34, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "The narrative technique of stream of consciousness creates intimacy with the reader."}, "answer": "Narativna tehnika toka svijesti stvara intimnost s čitaocem.", "hint": "Složena nominalna fraza kao subjekt"},
        {"id": 35, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "Without literary-historical context, the work cannot be understood."}, "answer": "Bez književnohistorijskog konteksta, djelo se ne može razumjeti.", "hint": "Negacija + bezlična konstrukcija"},
        {"id": 36, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "The novel, which is considered a masterpiece, deals with the theme of guilt."}, "answer": "Roman, koji se smatra remek-djelom, bavi se temom krivnje.", "hint": "Relativna klauza + refleksivni glagol"},
        {"id": 37, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "Every judgment must be supported by a quotation and interpretation."}, "answer": "Svaku ocjenu treba podupreti citatom i tumačenjem.", "hint": "Bezlično 'treba + infinitiv'"},
        {"id": 38, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "It can be observed that existentialism permeates Selimović's prose."}, "answer": "Može se uočiti da egzistencijalizam prožima Selimovićevu prozu.", "hint": "Bezlična konstrukcija + neupravni govor"},
        {"id": 39, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "The protagonist, whose fate is tragic, suffers because of the system."}, "answer": "Protagonist, čija je sudbina tragična, trpi zbog sistema.", "hint": "Posvojna relativna zamjenica 'čija'"},
        {"id": 40, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "The work could be read as an allegory of Bosnian identity."}, "answer": "Djelo bi se moglo čitati kao alegorija bosanskog identiteta.", "hint": "Kondicional za alternativno tumačenje"},
        {"id": 41, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Selimovićev roman je bogata alegorija ljudskog stanja."}, "answer": "Selimović's novel is a rich allegory of the human condition.", "hint": "alegorija = allegory"},
        {"id": 42, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Egzistencijalizam prožima Selimovićevu prozu."}, "answer": "Existentialism permeates Selimović's prose.", "hint": "egzistencijalizam = existentialism"},
        {"id": 43, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Ironija u Andrićevim pripovijetkama je višeslojna."}, "answer": "The irony in Andrić's stories is multilayered.", "hint": "ironija = irony"},
