        {"id": 45, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Tok svijesti je dominantna narativna tehnika."}, "answer": "Stream of consciousness is the dominant narrative technique.", "hint": "tok svijesti = stream of consciousness"},
        {"id": 46, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Simbolizam u poeziji Alekse Šantića je izražen."}, "answer": "Symbolism in the poetry of Aleksa Šantić is pronounced.", "hint": "simbolizam = symbolism"},
        {"id": 47, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Tematska os romana je sukob identiteta."}, "answer": "The thematic axis of the novel is the conflict of identity.", "hint": "tematska os = thematic axis"},
        {"id": 48, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Književni lik Nurudina je kompleksan i kontradiktorni."}, "answer": "The literary character of Nurudin is complex and contradictory.", "hint": "književni lik = literary character"},
        {"id": 49, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Realizam je dominantni književni pravac 19. stoljeća."}, "answer": "Realism is the dominant literary movement of the 19th century.", "hint": "književni pravac = literary movement"},
        {"id": 50, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Intertekstualnost ovog romana upućuje na Dostojevskog."}, "answer": "The intertextuality of this novel points to Dostoyevsky.", "hint": "intertekstualnost = intertextuality"},
        {"id": 51, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "U književnoj analizi, kojim glagolskim vremenom opisujemo radnje u tekstu?", "options": ["perfektom", "futurom", "prezentom", "imperfektom"]}, "answer": "prezentom", "hint": "Historijski prezent u književnoj analizi"},
